var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관 소유 안전가옥</color>\\n총격전 발생 10분 전","JPN":"<color=#ffd34c>プリドウェン機関所有のセーフハウス</color>\\n銃撃戦発生の10分前","ENG":"[[","TWN":"<color=#ffd34c>普利多溫機關的藏身處</color>\\n槍戰發生前10分鐘","THA":"<color=#ffd34c>เซฟเฮาส์ของสถาบันพริดเว็น</color>\\n10 นาทีก่อนเกิดเหตุยิงกัน","VTN":"<color=#ffd34c>Nhà An Toàn của Học Viện Prydwen</color>\\n10 phút trước vụ nổ súng","SCN":"<color=#ffd34c>普利多温机关的安全屋</color>\\n枪战发生10分钟前","DEU":"<color=#ffd34c>Geheimer Unterschlupf des Prydwen-Instituts</color>\\n10 Minuten vor der Schießerei","FRA":"<color=#ffd34c>Propriété sécurisée de l'Institut Prydwen</color>\\n10 minutes avant la fusillade"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아저씨들, 뭐 좀 나왔어?","JPN":"おっさんたち、何か出たか？","ENG":"Hey, you guys see anything?","TWN":"大叔們，有什麼發現嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"하하. 그랬으면 요원님 통신기가 정신없이 울렸겠지.","JPN":"はは。出てたら通信機が鳴りっぱなしだったろう。","ENG":"Haha. If we did, your comms would be pinging nonstop.","TWN":"哈哈，真有發現的話，你的通訊設備該響個不停了。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"책상에 피자 남은 거 있어. 먹고 나서 해.","JPN":"机に余ったピザがあるぞ。食べてからやれ。","ENG":"There's pizza left on the desk. Eat first.","TWN":"桌子上有剩下的披薩，吃完再繼續吧。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 이게. 골방에 처박혀서 맛없는 냉동 피자나 씹고.","JPN":"なんだよ、これ。小部屋に閉じこもってまずい冷凍ピザなんかかじってよ。","ENG":"Ugh... Eating frozen pizza in a stuffy room...","TWN":"這叫什麼事嘛，待在小屋裡吃著難以下嚥的冷凍披薩。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>교수</color>라는 인간, 정말 여기 나타나는 거 맞아?","JPN":"その<color=#ffd34c>教授</color>って人間、本当にここに現れるのか？","ENG":"The <color=#ffd34c>Professor</color>, are you sure he's going to be here?","TWN":"那個叫<color=#ffd34c>教授</color>的人，真的會出現在這裡嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"신뢰할 수 있는 정보처로부터 받은 소식이야.","JPN":"信頼できる情報元からのリークだ。","ENG":"It's from a highly credible source.","TWN":"消息來源是可靠的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 조심해야지. 학부장 중에서도 특히 거물 취급 받는 놈이니까.","JPN":"それでも気をつけないと。学部長の中でも特に大物とされている奴だからな。","ENG":"Just be careful. He's considered one of the big fish of the deans.","TWN":"那也要小心才行。他在眾多學院院長中，也是大人物。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터도 아니면서, 그 버넷 경도 은퇴하시기 전까지 결판을 못 낸 강적이거든.","JPN":"カウンターでもないのに、あのバーネット卿も引退するまで決着をつけられなかった強敵なんだ。","ENG":"He's not even a Counter, and Sir Burnett couldn't even take him down before he retired.","TWN":"明明不是制裁者，但在伯內特卿退休前，卻也沒能和他分出勝負。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하. 나사 빠진 우리 할배가 뭐 그리 대단하다고.","JPN":"ハッ。うちの間抜けジジイのどこがすげえってのか、わけわかんねえ。","ENG":"*Sigh* What was so great about my crazy Grandpa anyway?","TWN":"唉，那個老掉牙的爺爺，有什麼了不起的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 그 말 잠복 중인 친구들에게 하면 무척 섭섭해할 거야.","JPN":"はは、その言葉、張り込み中の奴らにするととても残念がるぞ。","ENG":"Haha! Your undercover friends will get upset if you say that in front of them.","TWN":"哈哈，你對潛伏中的同伴說這種話，可是會傷心的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"중대장님, 나타났습니다! 인상착의도 일치합니다!","JPN":"中隊長、現れました！　人相書きとほぼ一致します！","ENG":"Sir! He's here! The description is a perfect match!","TWN":"中隊長，出現了！衣著打扮也一致！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 카메라 당겨 봐, 어서!","JPN":"何？　ズームしろ、早く！","ENG":"What? Zoom in on the camera, quick!","TWN":"什麼？拉近鏡頭，快點！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 인간이 그렇게 악랄한 놈이라고? 실물은 더 공붓벌레처럼 생겼는데?","JPN":"この人間がそんなあくどい奴なのか？　実物はもっとガリ勉っぽいけど。","ENG":"Are you sure it's him? He looks more of a bookworm than a vicious criminal, no?","TWN":"這個人真的是凶神惡煞的傢伙？本人看起來更像書呆子呢？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"범죄 단체에게 대량 살상 무기의 알선, 테러 계획 지원, 국가 기밀 탈취……","JPN":"犯罪団体に大量の殺傷武器を斡旋、テロ計画の支援、国家機密の奪取……","ENG":"Providing weapons of mass destruction to criminal organizations, funding terrorist organizations, stealing national secrets...","TWN":"向犯罪組織介紹大量殺傷性武器，支援恐怖襲擊計畫，竊取國家機密……"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};